# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets

# Inventory dictionary to store player inventories
inventories = {}

# Function to handle inventory trade requests
async def trade(websocket, path):
    # Receive trade request data
    request = await websocket.recv()

    # Parse trade request data
    player1, player2, item = request.split()

    # Check if both players have the item
    if item in inventories[player1] and item in inventories[player2]:
        # Transfer item from player1 to player2
        inventories[player2].append(item)
        inventories[player1].remove(item)

        # Send confirmation message to both players
        await websocket.send("Item successfully traded.")
        await websocket.send(f"{item} traded from {player1} to {player2}.")
    else:
        # Send error message if one or both players don't have the item
        await websocket.send("Error: One or both players don't have the item.")

# Create WebSocket server
server = websockets.WSServer(trade)

# Start the server
asyncio.get_event_loop().run_until_complete(server(host="0.0.0.0", port=8765))

# Run the server indefinitely
asyncio.get_event_loop().run_forever()